package main

import (
	"encoding/gob"
	"fmt"
	"io/ioutil"
	"os"
	"path/filepath"
	"sync"
	"time"
)

type Session struct {
	UserID       string
	Preferences  map[string]interface{}
	Permissions  []string
	LastAccessed time.Time
}

type SessionManager struct {
	sessions map[string]*Session
	mu       sync.RWMutex
	dir      string
}

func NewSessionManager(sessionDir string) (*SessionManager, error) {
	if err := os.MkdirAll(sessionDir, 0755); err != nil {
		return nil, err
	}
	
	manager := &SessionManager{
		sessions: make(map[string]*Session),
		dir:      sessionDir,
	}
	
	manager.loadAllSessions()
	return manager, nil
}

func (sm *SessionManager) CreateSession(userID string) (*Session, error) {
	session := &Session{
		UserID:       userID,
		Preferences:  make(map[string]interface{}),
		Permissions:  make([]string, 0),
		LastAccessed: time.Now(),
	}
	
	sm.mu.Lock()
	sm.sessions[userID] = session
	sm.mu.Unlock()
	
	if err := sm.saveSession(userID, session); err != nil {
		return nil, err
	}
	
	return session, nil
}

func (sm *SessionManager) GetSession(userID string) (*Session, bool) {
	sm.mu.RLock()
	defer sm.mu.RUnlock()
	
	session, exists := sm.sessions[userID]
	if !exists {
		return nil, false
	}
	
	session.LastAccessed = time.Now()
	return session, true
}

func (sm *SessionManager) UpdateSession(userID string, updateFunc func(*Session)) error {
	sm.mu.Lock()
	defer sm.mu.Unlock()
	
	session, exists := sm.sessions[userID]
	if !exists {
		return fmt.Errorf("session not found for user: %s", userID)
	}
	
	updateFunc(session)
	session.LastAccessed = time.Now()
	
	return sm.saveSession(userID, session)
}

func (sm *SessionManager) DeleteSession(userID string) error {
	sm.mu.Lock()
	defer sm.mu.Unlock()
	
	delete(sm.sessions, userID)
	
	sessionPath := filepath.Join(sm.dir, userID+".gob")
	return os.Remove(sessionPath)
}

func (sm *SessionManager) saveSession(userID string, session *Session) error {
	sessionPath := filepath.Join(sm.dir, userID+".gob")
	
	file, err := os.Create(sessionPath)
	if err != nil {
		return err
	}
	defer file.Close()
	
	encoder := gob.NewEncoder(file)
	return encoder.Encode(session)
}

func (sm *SessionManager) loadAllSessions() error {
	files, err := ioutil.ReadDir(sm.dir)
	if err != nil {
		return err
	}
	
	for _, file := range files {
		if filepath.Ext(file.Name()) == ".gob" {
			userID := strings.TrimSuffix(file.Name(), ".gob")
			if err := sm.loadSession(userID); err != nil {
				fmt.Printf("Failed to load session for user %s: %v\n", userID, err)
			}
		}
	}
	
	return nil
}

func (sm *SessionManager) loadSession(userID string) error {
	sessionPath := filepath.Join(sm.dir, userID+".gob")
	
	file, err := os.Open(sessionPath)
	if err != nil {
		return err
	}
	defer file.Close()
	
	var session Session
	decoder := gob.NewDecoder(file)
	if err := decoder.Decode(&session); err != nil {
		return err
	}
	
	sm.mu.Lock()
	sm.sessions[userID] = &session
	sm.mu.Unlock()
	
	return nil
}

func (sm *SessionManager) CleanupExpiredSessions(expiration time.Duration) {
	sm.mu.Lock()
	defer sm.mu.Unlock()
	
	now := time.Now()
	for userID, session := range sm.sessions {
		if now.Sub(session.LastAccessed) > expiration {
			delete(sm.sessions, userID)
			sessionPath := filepath.Join(sm.dir, userID+".gob")
			os.Remove(sessionPath)
		}
	}
}

func (sm *SessionManager) Close() error {
	sm.mu.Lock()
	defer sm.mu.Unlock()
	
	for userID, session := range sm.sessions {
		if err := sm.saveSession(userID, session); err != nil {
			return err
		}
	}
	
	return nil
}

